% figure( 'Name', [fitModel ' Fit'] );
% h = plot( fitresult, tData, yData );
% legend( h, 'concentration vs. time', 'CA Arrival Time Fit', 'Location', 'NorthEast' );
% % Label axes
% xlabel time
% ylabel concentration
% grid on